function Test-GlobMatch {
    # Test if a file path matches a glob pattern
    param(
        [string]$Path,
        [string]$Pattern
    )

    # Convert glob pattern to regex
    # Handle ** (any number of directories), * (any characters in segment), ? (single char)
    $regexPattern = $Pattern `
        -replace '\.', '\.' `  # Escape dots
        -replace '\*\*', '.*' `  # ** matches anything
        -replace '\*', '[^/]*' `  # * matches anything except /
        -replace '\?', '.' # ? matches single char

    # Anchor the pattern
    $regexPattern = "^$regexPattern$"

    return $Path -match $regexPattern
}

function Get-PrLabels {
    <#
    .SYNOPSIS
    Applies labels to files based on configurable path-to-label mapping rules.

    .DESCRIPTION
    Takes a list of file paths and applies labels based on matching rules.
    Rules can have glob patterns and priority values. When multiple rules match
    the same file, only the highest priority rules' labels are applied.

    .PARAMETER Files
    Array of file paths to process.

    .PARAMETER Rules
    Array of rule objects with pattern, labels, and priority properties.
    #>
    param(
        [string[]]$Files,
        [array]$Rules
    )

    $allLabels = @()

    foreach ($file in $Files) {
        # Find all rules that match this file
        $matchingRules = @()

        foreach ($rule in $Rules) {
            if (Test-GlobMatch -Path $file -Pattern $rule.pattern) {
                $matchingRules += $rule
            }
        }

        # If no rules match, skip this file
        if ($matchingRules.Count -eq 0) {
            continue
        }

        # Find the highest priority among matching rules
        $maxPriority = ($matchingRules | Measure-Object -Property priority -Maximum).Maximum

        # Get labels from rules with the highest priority
        foreach ($rule in $matchingRules) {
            if ($rule.priority -eq $maxPriority) {
                $allLabels += $rule.labels
            }
        }
    }

    # Return unique labels, sorted for consistent output
    return $allLabels | Sort-Object -Unique
}

