    Write-Host "  Labels: $($labels -join ', ')" -ForegroundColor Green
} else {
    Write-Host "✗ Test case 3 failed: Missing labels: $($missingLabels -join ', ')" -ForegroundColor Red
}

# Test case 4: Config validation
